import{bQ as d,aL as e,u as o,G as a}from"./chunks/framework.D06dwy5q.js";const p=JSON.parse('{"title":"需求边界","description":"","frontmatter":{},"headers":[],"relativePath":"20. Python后端开发/03. 运维平台项目实战/01-需求边界.md","filePath":"20. Python后端开发/03. 运维平台项目实战/01-需求边界.md","lastUpdated":null}'),r={name:"20. Python后端开发/03. 运维平台项目实战/01-需求边界.md"};function c(h,t,i,l,s,b){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="需求边界" tabindex="-1">需求边界 <a class="header-anchor" href="#需求边界" aria-label="Permalink to &quot;需求边界&quot;">​</a></h1><p><code>ops-console</code> 是一个很小的内部运维平台练习项目，用来把轻量前端、FastAPI、数据库、认证、任务、Webhook、审计和部署串起来。当前代码围绕登录、目标、任务、事件和审计几类对象展开；审批、多租户、实时通知和任务队列还没有对应表结构和接口。</p><p>核心对象关系很直接：目标表示要检查的对象，任务表示一次检查或一次手动操作，事件表示外部系统推来的 Webhook，用户提供登录身份，审计日志记录谁做了什么。</p><h2 id="一、范围" tabindex="-1">一、范围 <a class="header-anchor" href="#一、范围" aria-label="Permalink to &quot;一、范围&quot;">​</a></h2><p>当前功能范围：</p><table tabindex="0"><thead><tr><th>模块</th><th>内容</th></tr></thead><tbody><tr><td>登录</td><td>用户登录，返回 JWT</td></tr><tr><td>目标管理</td><td>新增、查询、修改、删除检查目标</td></tr><tr><td>任务管理</td><td>手动触发检查，查询任务状态和日志</td></tr><tr><td>Webhook</td><td>接收 GitLab 和 Alertmanager 事件</td></tr><tr><td>审计</td><td>记录关键操作，支持查询</td></tr><tr><td>前端</td><td>登录页、目标列表、任务详情、事件列表、审计列表</td></tr><tr><td>发布</td><td>前端静态构建、后端镜像、Compose 或 K8s 部署</td></tr></tbody></table><p>还没有进入代码的内容：</p><table tabindex="0"><thead><tr><th>内容</th><th>当前状态</th></tr></thead><tbody><tr><td>多租户</td><td>没有组织表、租户字段和数据隔离逻辑</td></tr><tr><td>复杂审批</td><td>任务触发只按角色判断</td></tr><tr><td>实时 WebSocket</td><td>任务状态通过接口查询</td></tr><tr><td>大规模任务队列</td><td>任务状态写在数据库里，执行靠后台任务</td></tr><tr><td>复杂菜单系统</td><td>前端只按角色显示少量入口</td></tr></tbody></table><p><code>targets</code>、<code>tasks</code>、<code>events</code>、<code>audit_logs</code> 几张表能和接口、页面一一对应。</p><h2 id="二、用户角色" tabindex="-1">二、用户角色 <a class="header-anchor" href="#二、用户角色" aria-label="Permalink to &quot;二、用户角色&quot;">​</a></h2><p>当前只有两个角色：</p><table tabindex="0"><thead><tr><th>角色</th><th>权限</th></tr></thead><tbody><tr><td><code>admin</code></td><td>管理用户、目标、任务、Webhook、审计</td></tr><tr><td><code>operator</code></td><td>查看目标、触发任务、查看事件和任务结果</td></tr></tbody></table><p>角色不做成复杂权限矩阵。后端先用依赖函数判断角色，前端根据当前用户角色隐藏部分入口。</p><h2 id="三、页面清单" tabindex="-1">三、页面清单 <a class="header-anchor" href="#三、页面清单" aria-label="Permalink to &quot;三、页面清单&quot;">​</a></h2><p>前端页面：</p><table tabindex="0"><thead><tr><th>页面</th><th>路径</th><th>内容</th></tr></thead><tbody><tr><td>登录</td><td><code>/login</code></td><td>用户名、密码、错误提示</td></tr><tr><td>首页</td><td><code>/</code></td><td>最近任务、最近事件</td></tr><tr><td>目标列表</td><td><code>/targets</code></td><td>查询、新增、编辑、删除目标</td></tr><tr><td>任务列表</td><td><code>/tasks</code></td><td>状态筛选、任务记录</td></tr><tr><td>任务详情</td><td><code>/tasks/:id</code></td><td>任务状态、日志、结果</td></tr><tr><td>事件列表</td><td><code>/events</code></td><td>Webhook 事件查询</td></tr><tr><td>审计日志</td><td><code>/audit-logs</code></td><td>操作记录查询</td></tr></tbody></table><p>前端页面以普通管理页为主，内容集中在数据表格、表单、详情页、错误提示和 loading 状态。</p><h2 id="四、接口清单" tabindex="-1">四、接口清单 <a class="header-anchor" href="#四、接口清单" aria-label="Permalink to &quot;四、接口清单&quot;">​</a></h2><p>后端接口：</p><table tabindex="0"><thead><tr><th>方法</th><th>路径</th><th>说明</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/api/v1/auth/token</code></td><td>登录</td></tr><tr><td><code>GET</code></td><td><code>/api/v1/users/me</code></td><td>当前用户</td></tr><tr><td><code>GET</code></td><td><code>/api/v1/targets</code></td><td>目标列表</td></tr><tr><td><code>POST</code></td><td><code>/api/v1/targets</code></td><td>创建目标</td></tr><tr><td><code>PUT</code></td><td><code>/api/v1/targets/{id}</code></td><td>更新目标</td></tr><tr><td><code>DELETE</code></td><td><code>/api/v1/targets/{id}</code></td><td>删除目标</td></tr><tr><td><code>POST</code></td><td><code>/api/v1/tasks</code></td><td>手动创建任务</td></tr><tr><td><code>GET</code></td><td><code>/api/v1/tasks</code></td><td>任务列表</td></tr><tr><td><code>GET</code></td><td><code>/api/v1/tasks/{id}</code></td><td>任务详情</td></tr><tr><td><code>GET</code></td><td><code>/api/v1/tasks/{id}/logs</code></td><td>任务日志</td></tr><tr><td><code>POST</code></td><td><code>/api/v1/webhooks/gitlab</code></td><td>GitLab 事件</td></tr><tr><td><code>POST</code></td><td><code>/api/v1/webhooks/alertmanager</code></td><td>Alertmanager 事件</td></tr><tr><td><code>GET</code></td><td><code>/api/v1/events</code></td><td>事件列表</td></tr><tr><td><code>GET</code></td><td><code>/api/v1/audit-logs</code></td><td>审计列表</td></tr></tbody></table><p>接口统一放在 <code>/api/v1</code> 下。前端请求也统一从这个前缀开始，做 Nginx 反代时路径更清楚。</p><h2 id="五、数据对象" tabindex="-1">五、数据对象 <a class="header-anchor" href="#五、数据对象" aria-label="Permalink to &quot;五、数据对象&quot;">​</a></h2><p>核心对象：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20user%5B%22User%3Cbr%2F%3E%E7%94%A8%E6%88%B7%22%5D%20--%3E%20audit%5B%22AuditLog%3Cbr%2F%3E%E5%AE%A1%E8%AE%A1%E6%97%A5%E5%BF%97%22%5D%0A%20%20%20%20target%5B%22Target%3Cbr%2F%3E%E6%A3%80%E6%9F%A5%E7%9B%AE%E6%A0%87%22%5D%20--%3E%20task%5B%22Task%3Cbr%2F%3E%E4%BB%BB%E5%8A%A1%22%5D%0A%20%20%20%20task%20--%3E%20tasklog%5B%22TaskLog%3Cbr%2F%3E%E4%BB%BB%E5%8A%A1%E6%97%A5%E5%BF%97%22%5D%0A%20%20%20%20webhook%5B%22Webhook%20Event%3Cbr%2F%3E%E5%A4%96%E9%83%A8%E4%BA%8B%E4%BB%B6%22%5D%20--%3E%20event%5B%22EventRecord%3Cbr%2F%3E%E4%BA%8B%E4%BB%B6%E8%AE%B0%E5%BD%95%22%5D%0A%20%20%20%20user%20--%3E%20task%0A"></div><p>几个关系：</p><table tabindex="0"><thead><tr><th>关系</th><th>说明</th></tr></thead><tbody><tr><td>用户创建目标</td><td>审计记录里保存 actor</td></tr><tr><td>用户触发任务</td><td>任务表记录 created_by</td></tr><tr><td>任务关联目标</td><td>一次任务可以检查一个目标</td></tr><tr><td>任务产生日志</td><td>任务执行过程写入 TaskLog</td></tr><tr><td>Webhook 进入事件表</td><td>原始 payload 保存在 EventRecord</td></tr></tbody></table><p>当前模型没有多对多关系表。目标和任务按一对多处理。</p><h2 id="六、项目范围" tabindex="-1">六、项目范围 <a class="header-anchor" href="#六、项目范围" aria-label="Permalink to &quot;六、项目范围&quot;">​</a></h2><p><code>ops-console</code> 的定位是练习型内部平台，不是一次性做成生产系统。它要覆盖的是：</p><ol><li>后端接口和数据库模型如何配合。</li><li>前端如何调用接口、处理状态和错误。</li><li>后台任务如何有状态、有日志。</li><li>Webhook 如何接收、校验、入库。</li><li>审计和权限如何嵌入关键操作。</li><li>项目如何构建、打镜像、部署运行。</li></ol><p>目录、模型、后端接口、任务、Webhook、前端页面、权限审计、镜像和发布文件都有固定落点。读代码时能看出每一块接到哪里，也能看出哪些对象还没有表、路由或页面。</p>',31)])])}const E=d(r,[["render",c]]);export{p as __pageData,E as default};
